{
  "name": "AI-City Navigator & Traffic Control",
  "description": "An advanced Smart City ecosystem for 2026, integrating LLM-powered pedestrian routing, dynamic traffic management, and public transport prioritization for Almaty's Golden Square.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ViewMode {
  OVERVIEW = 'OVERVIEW',
  PEDESTRIAN = 'PEDESTRIAN',
  TRAFFIC = 'TRAFFIC',
  ANALYTICS = 'ANALYTICS'
}

export interface SmartPoint {
  id: string;
  lat: number;
  lng: number;
  type: 'traffic-light' | 'sensor' | 'bus-stop';
  status: 'normal' | 'optimized' | 'alert';
  value?: number;
}

export interface RouteStep {
  instruction: string;
  reason: string;
  environmentalBenefit: string;
}

export interface NavigationResult {
  route: RouteStep[];
  totalQuietness: number;
  greeneryIndex: number;
  airQuality: string;
}

import { GoogleGenAI, Type } from "@google/genai";

const API_KEY = process.env.API_KEY || "";

export const getSmartRoute = async (userPrompt: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Act as a Smart City Navigation AI for Almaty. 
    User request: "${userPrompt}"

    The user is asking for a pedestrian route in the 'Golden Square' (Abay, Abylai Khan, Kenesary, Kaldayakov).
    Identify the start and end points from the request.
    Recommend a path that prioritizes: 
    1. Low noise levels (avoiding busy Abay if possible, using Panfilov).
    2. High greenery/shade (using Tulebayev or park zones).
    3. Safety and air quality.

    Respond in JSON format.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          route: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                instruction: { type: Type.STRING },
                reason: { type: Type.STRING, description: "Why this path was chosen (e.g. 'high greenery', 'low noise')" },
                environmentalBenefit: { type: Type.STRING }
              }
            }
          },
          totalQuietness: { type: Type.NUMBER, description: "Scale 0-100" },
          greeneryIndex: { type: Type.NUMBER, description: "Scale 0-100" },
          airQuality: { type: Type.STRING, description: "PM2.5 rating" }
        },
        required: ["route", "totalQuietness", "greeneryIndex", "airQuality"]
      }
    }
  });

  return JSON.parse(response.text || "{}");
};

export const getTrafficInsights = async (stats: any) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze this real-time city traffic data and provide a management summary: ${JSON.stringify(stats)}. 
    Suggest 3 immediate actions for the Adaptive Traffic Control system in Almaty's center.`,
  });
  return response.text;
};

