export default Sidebar;

import React, { useState, useEffect } from 'react';
import { SmartPoint } from '../types';

const CityMap: React.FC = () => {
  const [points, setPoints] = useState<SmartPoint[]>([]);

  // Generate random sensor points for Almaty Golden Square
  useEffect(() => {
    const initialPoints: SmartPoint[] = [
      { id: '1', lat: 20, lng: 30, type: 'traffic-light', status: 'optimized', value: 45 },
      { id: '2', lat: 50, lng: 15, type: 'sensor', status: 'normal', value: 12 },
      { id: '3', lat: 70, lng: 40, type: 'bus-stop', status: 'normal', value: 88 },
      { id: '4', lat: 40, lng: 80, type: 'traffic-light', status: 'alert', value: 120 },
      { id: '5', lat: 80, lng: 70, type: 'sensor', status: 'optimized', value: 5 },
    ];
    setPoints(initialPoints);
  }, []);

  return (
    <div className="relative w-full h-[500px] bg-slate-950 rounded-2xl overflow-hidden border border-slate-800 group">
      {/* Visual Mock of Almaty Grid */}
      <svg viewBox="0 0 100 100" className="w-full h-full opacity-40">
        {/* Horizontal Streets */}
        <line x1="0" y1="20" x2="100" y2="20" stroke="#334155" strokeWidth="0.5" />
        <line x1="0" y1="40" x2="100" y2="40" stroke="#334155" strokeWidth="0.5" />
        <line x1="0" y1="60" x2="100" y2="60" stroke="#334155" strokeWidth="0.5" />
        <line x1="0" y1="80" x2="100" y2="80" stroke="#334155" strokeWidth="1" /> {/* Abay */}

        {/* Vertical Streets */}
        <line x1="20" y1="0" x2="20" y2="100" stroke="#334155" strokeWidth="0.5" />
        <line x1="40" y1="0" x2="40" y2="100" stroke="#334155" strokeWidth="0.5" />
        <line x1="60" y1="0" x2="60" y2="100" stroke="#334155" strokeWidth="1" /> {/* Abylai Khan */}
        <line x1="80" y1="0" x2="80" y2="100" stroke="#334155" strokeWidth="0.5" />

        {/* Panfilov Promenade (Pedestrian) */}
        <line x1="50" y1="0" x2="50" y2="100" stroke="#10b981" strokeWidth="2" strokeDasharray="2" opacity="0.6" />

        {/* Traffic Animations */}
        <circle r="0.8" fill="#fbbf24" className="animate-pulse">
          <animateMotion path="M 0 40 L 100 40" dur="8s" repeatCount="indefinite" />
        </circle>
        <circle r="0.8" fill="#fbbf24" className="animate-pulse">
          <animateMotion path="M 100 20 L 0 20" dur="12s" repeatCount="indefinite" />
        </circle>
        <rect width="2" height="1" fill="#3b82f6">
           <animateMotion path="M 60 0 L 60 100" dur="6s" repeatCount="indefinite" />
        </rect>
      </svg>

      {/* Point Overlays */}
      {points.map((p) => (
        <div
          key={p.id}
          className="absolute transform -translate-x-1/2 -translate-y-1/2 cursor-pointer transition-transform hover:scale-125"
          style={{ top: `${p.lat}%`, left: `${p.lng}%` }}
        >
          <div className={`
            p-1.5 rounded-full border shadow-xl
            ${p.status === 'optimized' ? 'bg-emerald-500/20 border-emerald-500' : 
              p.status === 'alert' ? 'bg-rose-500/20 border-rose-500' : 'bg-blue-500/20 border-blue-500'}
          `}>
             <i className={`fas ${
               p.type === 'traffic-light' ? 'fa-traffic-light' : 
               p.type === 'bus-stop' ? 'fa-bus' : 'fa-satellite-dish'
             } text-[10px]`}></i>
          </div>
          {p.status === 'alert' && (
             <div className="absolute -top-1 -right-1 bg-rose-500 w-2 h-2 rounded-full animate-ping"></div>
          )}
        </div>
      ))}

      {/* Info Legend */}
      <div className="absolute bottom-4 left-4 bg-slate-900/80 backdrop-blur border border-slate-800 p-3 rounded-xl text-[10px] space-y-1">
        <div className="flex items-center space-x-2">
          <span className="w-2 h-2 rounded-full bg-emerald-500"></span>
          <span>AI Optimized Phase</span>
        </div>
        <div className="flex items-center space-x-2">
          <span className="w-2 h-2 rounded-full bg-rose-500"></span>
          <span>Congestion Detected</span>
        </div>
        <div className="flex items-center space-x-2">
          <span className="w-2 h-2 border border-emerald-500 border-dashed"></span>
          <span>Pedestrian Comfort Zone</span>
        </div>
      </div>

      <div className="absolute top-4 right-4 text-xs font-mono bg-slate-900/60 p-2 rounded border border-slate-800">
        LOC: 43.2389° N, 76.9455° E
      </div>
    </div>
