};

export default CityMap;

import React, { useState } from 'react';
import { getSmartRoute } from '../services/geminiService';
import { NavigationResult } from '../types';

const LlmNavigator: React.FC = () => {
  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<NavigationResult | null>(null);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    try {
      const data = await getSmartRoute(query);
      setResult(data);
    } catch (error) {
      console.error("Navigation Error:", error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full">
      <div className="bg-slate-800/40 p-6 rounded-2xl border border-slate-700/50">
        <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
          <i className="fas fa-brain text-emerald-400"></i>
          Pedestrian Environmental AI
        </h2>
        <form onSubmit={handleSearch} className="relative">
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Try: 'Walk from Panfilov to Abylai Khan through the greenest path'"
            className="w-full bg-slate-900 border border-slate-700 rounded-xl px-5 py-4 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/50 pr-12"
          />
          <button 
            type="submit"
            disabled={loading}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-emerald-500 p-2 hover:bg-emerald-500/10 rounded-lg transition-colors"
          >
            {loading ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-arrow-right"></i>}
          </button>
        </form>
      </div>

      <div className="mt-6 flex-1 overflow-y-auto pr-2">
        {result ? (
          <div className="space-y-6">
            <div className="grid grid-cols-3 gap-4">
              <div className="bg-slate-800/30 p-4 rounded-xl border border-slate-700/30 text-center">
                <p className="text-[10px] text-slate-500 uppercase font-bold mb-1">Quietness</p>
                <p className="text-2xl font-bold text-emerald-400">{result.totalQuietness}%</p>
              </div>
              <div className="bg-slate-800/30 p-4 rounded-xl border border-slate-700/30 text-center">
                <p className="text-[10px] text-slate-500 uppercase font-bold mb-1">Greenery</p>
                <p className="text-2xl font-bold text-emerald-400">{result.greeneryIndex}%</p>
              </div>
              <div className="bg-slate-800/30 p-4 rounded-xl border border-slate-700/30 text-center">
                <p className="text-[10px] text-slate-500 uppercase font-bold mb-1">Air Quality</p>
                <p className="text-xl font-bold text-emerald-400">{result.airQuality}</p>
              </div>
            </div>

            <div className="space-y-4">
              <h3 className="font-semibold text-slate-300 px-1">Recommended Intelligent Path:</h3>
              {result.route.map((step, idx) => (
                <div key={idx} className="flex gap-4 group">
                  <div className="flex flex-col items-center">
                    <div className="w-8 h-8 rounded-full bg-slate-800 border border-emerald-500/30 flex items-center justify-center text-xs font-bold text-emerald-400">
                      {idx + 1}
                    </div>
                    {idx < result.route.length - 1 && <div className="w-px h-full bg-slate-700/50 mt-1"></div>}
                  </div>
                  <div className="flex-1 bg-slate-800/20 p-4 rounded-xl border border-slate-700/30 group-hover:bg-slate-800/40 transition-colors">
                    <p className="text-sm font-medium">{step.instruction}</p>
                    <div className="mt-2 flex flex-wrap gap-2">
                      <span className="text-[10px] bg-emerald-500/10 text-emerald-400 px-2 py-0.5 rounded-full border border-emerald-500/20">
                        <i className="fas fa-leaf mr-1"></i> {step.reason}
                      </span>
                      <span className="text-[10px] bg-blue-500/10 text-blue-400 px-2 py-0.5 rounded-full border border-blue-500/20">
                        <i className="fas fa-shield-alt mr-1"></i> {step.environmentalBenefit}
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div className="h-full flex flex-col items-center justify-center text-slate-500 space-y-4 text-center p-12">
            <i className="fas fa-location-arrow text-4xl opacity-20"></i>
            <p>Ready to plan your next environment-aware walk in Almaty.</p>
            <div className="flex gap-2">
              <span className="px-3 py-1 bg-slate-800 rounded-full text-xs hover:text-emerald-400 cursor-pointer" onClick={() => setQuery("Quiet way to Kok Tobe")}>Kok Tobe</span>
              <span className="px-3 py-1 bg-slate-800 rounded-full text-xs hover:text-emerald-400 cursor-pointer" onClick={() => setQuery("Greenest path to Astana Square")}>Astana Square</span>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default LlmNavigator;

