const API_KEY = process.env.API_KEY || "";

export const getSmartRoute = async (userPrompt: string, lang: Language = 'en') => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const langContext = lang === 'ru' ? 'Respond in Russian language.' : (lang === 'kk' ? 'Respond in Kazakh language.' : 'Respond in English language.');

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Act as a Smart City Navigation AI for Almaty. 
    User request: "${userPrompt}"

    The user is asking for a pedestrian route in the 'Golden Square' (Abay, Abylai Khan, Kenesary, Kaldayakov).
    Identify the start and end points from the request.
    Recommend a path that prioritizes: 
    1. Low noise levels (avoiding busy Abay if possible, using Panfilov).
    2. High greenery/shade (using Tulebayev or park zones).
    3. Safety and air quality.

    ${langContext}
    Respond in JSON format.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          route: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                instruction: { type: Type.STRING },
                reason: { type: Type.STRING, description: "Why this path was chosen (e.g. 'high greenery', 'low noise')" },
                environmentalBenefit: { type: Type.STRING }
              }
            }
          },
          totalQuietness: { type: Type.NUMBER, description: "Scale 0-100" },
          greeneryIndex: { type: Type.NUMBER, description: "Scale 0-100" },
          airQuality: { type: Type.STRING, description: "PM2.5 rating" }
        },
        required: ["route", "totalQuietness", "greeneryIndex", "airQuality"]
      }
    }
  });

  return JSON.parse(response.text || "{}");
};

export const getTrafficInsights = async (stats: any, lang: Language = 'en') => {
