import React, { useState } from 'react';
import { getSmartRoute } from '../services/geminiService';
import { NavigationResult, Language } from '../types';
import { translations } from '../locales/translations';

interface LlmNavigatorProps {
  lang: Language;
}

const LlmNavigator: React.FC<LlmNavigatorProps> = ({ lang }) => {
  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<NavigationResult | null>(null);

  const t = translations[lang].pedestrian;

  const handleSearch = async (e: React.FormEvent | string) => {
    if (typeof e !== 'string') e.preventDefault();
    const finalQuery = typeof e === 'string' ? e : query;
    if (!finalQuery.trim()) return;

    setLoading(true);
    try {
      const data = await getSmartRoute(finalQuery, lang);
      setResult(data);
    } catch (error) {
      console.error("Navigation Error:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleSampleClick = (text: string) => {
    setQuery(text);
    handleSearch(text);
  };

  return (
    <div className="flex flex-col h-full">
      <div className="bg-slate-800/40 p-6 rounded-2xl border border-slate-700/50">
        <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
          <i className="fas fa-brain text-emerald-400"></i>
          {t.title}
        </h2>
        <form onSubmit={handleSearch} className="relative">
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder={t.placeholder}
            className="w-full bg-slate-900 border border-slate-700 rounded-xl px-5 py-4 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/50 pr-12"
          />
          <button 
            type="submit"
            disabled={loading}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-emerald-500 p-2 hover:bg-emerald-500/10 rounded-lg transition-colors"
          >
            {loading ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-arrow-right"></i>}
          </button>
        </form>
      </div>

      <div className="mt-6 flex-1 overflow-y-auto pr-2">
        {result ? (
