import { GoogleGenAI, Type } from "@google/genai";
import { Language } from "../types";

const API_KEY = process.env.API_KEY || "";

export const getSmartRoute = async (userPrompt: string, lang: Language = 'en') => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const langContext = lang === 'ru' ? 'Respond in Russian.' : (lang === 'kk' ? 'Respond in Kazakh.' : 'Respond in English.');

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Act as a Smart City Navigation AI for Almaty. 
    You have REAL-TIME access to:
    - SERGEK Traffic System (camera analytics, flow speed, YOLOv10 object detection).
    - AIRKAZ PM2.5 Network (pollution levels from sensor clusters).
    - OPENSTREETMAP (detailed tree data, bench locations, road surface types).
    - CITYBUS GPS (real-time bus locations and delay times).

    User request: "${userPrompt}"

    The user is asking for a pedestrian route in the 'Golden Square' (Abay, Abylai Khan, Kenesary, Kaldayakov).
    Analyze the request and provide a route that maximizes:
    - TREE SHADE (using OSM natural=tree tags).
    - AIR QUALITY (avoiding AirKaz high-pollution zones).
    - SAFETY (using Sergek pedestrian-heavy crossing data).

    ${langContext}
    Respond in JSON format.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          route: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                instruction: { type: Type.STRING },
                reason: { type: Type.STRING, description: "Mention Sergek or AirKaz data used" },
                environmentalBenefit: { type: Type.STRING }
              }
            }
          },
          totalQuietness: { type: Type.NUMBER },
          greeneryIndex: { type: Type.NUMBER },
          airQuality: { type: Type.STRING }
        },
        required: ["route", "totalQuietness", "greeneryIndex", "airQuality"]
      }
    }
  });

  return JSON.parse(response.text || "{}");
};

