            lat: Math.max(0, Math.min(100, mockLat)), 
            lng: Math.max(0, Math.min(100, mockLng)) 
          });
        },
        (error) => console.log("Geolocation error:", error),
        { enableHighAccuracy: true }
      );
      return () => navigator.geolocation.clearWatch(watchId);
    }
  }, []);

