          smartAdvice: { type: Type.STRING }
        },
        required: ["route", "totalQuietness", "greeneryIndex", "airQuality", "smartAdvice"]
      }
    }
  });

  const text = response.text || "{}";
  try {
    return JSON.parse(text);
  } catch (e) {
    console.error("Failed to parse AI response", text);
    throw e;
  }
};
